import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1781966466000}'),o={name:"guide/architecture.md"};function c(d,e,r,p,i,l){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="folder-structure" tabindex="-1">Folder structure <a class="header-anchor" href="#folder-structure" aria-label="Permalink to &quot;Folder structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>korovany/</span></span>
<span class="line"><span>├── .github/workflows/     # CI/CD: deploy.yml (Cloudflare Pages), docs.yml (GitHub Pages)</span></span>
<span class="line"><span>├── assets/                # source binary assets, tracked via Git LFS (models, textures, audio)</span></span>
<span class="line"><span>├── docs/                  # this VitePress documentation site → GitHub Pages</span></span>
<span class="line"><span>│   ├── .vitepress/        # docs site config</span></span>
<span class="line"><span>│   ├── guide/             # getting-started, project rules, architecture</span></span>
<span class="line"><span>│   └── operations/        # deployment &amp; credentials runbooks</span></span>
<span class="line"><span>├── public/                # static files served as-is at the web root</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── app/               # app shell &amp; top-level composition (App.tsx, full-page stage)</span></span>
<span class="line"><span>│   ├── components/        # reusable React UI components</span></span>
<span class="line"><span>│   ├── engine/            # Babylon Engine/Scene lifecycle (createGameEngine, resize, dispose)</span></span>
<span class="line"><span>│   ├── scenes/            # Babylon.js scenes + GameCanvas.tsx (thin React wrapper)</span></span>
<span class="line"><span>│   ├── game/              # engine-agnostic game logic (systems, entities, rules)</span></span>
<span class="line"><span>│   ├── store/             # Redux Toolkit store + slices, typed hooks</span></span>
<span class="line"><span>│   ├── hooks/             # shared React hooks</span></span>
<span class="line"><span>│   ├── assets/            # assets imported &amp; bundled by Vite</span></span>
<span class="line"><span>│   ├── styles/            # global styles</span></span>
<span class="line"><span>│   ├── types/             # shared TypeScript types</span></span>
<span class="line"><span>│   └── test/              # test setup (setup.ts)</span></span>
<span class="line"><span>├── AGENTS.md / CLAUDE.md  # rules for automated contributors</span></span>
<span class="line"><span>└── index.html             # Vite entry</span></span></code></pre></div><h2 id="where-new-code-goes" tabindex="-1">Where new code goes <a class="header-anchor" href="#where-new-code-goes" aria-label="Permalink to &quot;Where new code goes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You are adding…</th><th>Put it in…</th></tr></thead><tbody><tr><td>A Babylon scene/world</td><td><code>src/scenes/</code></td></tr><tr><td>Engine/render-loop lifecycle</td><td><code>src/engine/</code></td></tr><tr><td>Reusable UI (buttons, HUD)</td><td><code>src/components/</code></td></tr><tr><td>Game logic (no React/Babylon)</td><td><code>src/game/</code></td></tr><tr><td>Shared state</td><td><code>src/store/</code> (a new slice)</td></tr><tr><td>A 3D model / texture / sound</td><td><code>assets/</code> (tracked by Git LFS)</td></tr><tr><td>Documentation</td><td><code>docs/</code> (same change as the code)</td></tr></tbody></table><h2 id="data-flow" tabindex="-1">Data flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data flow&quot;">​</a></h2><p><code>main.tsx</code> mounts React inside a Redux <code>&lt;Provider&gt;</code> and renders the full-page app shell (<code>src/app/App.tsx</code>): a <code>100vw × 100vh</code> stage holding the 3D canvas with a HUD overlay. UI reads state via the typed <code>useAppSelector</code> hook and dispatches via <code>useAppDispatch</code> (both from <code>src/store</code>).</p><p>The Babylon lifecycle lives in <code>src/engine/</code>: <code>createGameEngine(canvas)</code> owns the <code>Engine</code>/<code>Scene</code>, the render loop, the high-DPI resize handler, and <code>dispose()</code>. The React side stays thin — <code>src/scenes/GameCanvas.tsx</code> only mounts the engine against a ref&#39;d canvas and disposes it on unmount. Engine code can read/dispatch to the same store, so game systems and UI stay in sync through Redux.</p><h2 id="game-loop" tabindex="-1">Game loop <a class="header-anchor" href="#game-loop" aria-label="Permalink to &quot;Game loop&quot;">​</a></h2><p>Simulation runs on a fixed timestep decoupled from render FPS, in <code>src/game/loop/</code> (engine-agnostic — no Babylon/React). A Babylon scene drives it by calling <code>loop.advance(deltaSeconds)</code> each render frame. See <a href="./game-loop">Game loop</a> for the system-registration API and how to add a system.</p>`,10)])])}const m=a(o,[["render",c]]);export{u as __pageData,m as default};
